1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ---- Simplest cases ----
6	  it("empty item list quote — premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // ---- Base premiums per item type ----
15	  it.todo("single sword (no modifiers, newcomer first contract) — base 100 + 10 first + 5 fee = 115 G");
16	  it.todo("single amulet (no modifiers, newcomer first contract) — base 60 + 6 first + 5 fee = 71 G");
17	  it.todo("single staff (no modifiers, newcomer first contract) — base 80 + 8 first + 5 fee = 93 G");
18	  it.todo("single potion (no modifiers, newcomer first contract) — base 40 + 4 first + 5 fee = 49 G");
19	
20	  // ---- Components: building blocks of 3 alike ----
21	  it.todo("2 runes — base 50 G (no block)");
22	  it.todo("3 runes — base 60 G (block applies)");
23	  it.todo("4 runes — base 100 G (no block: requires exactly 3)");
24	  it.todo("7 runes — base 175 G (no block)");
25	
26	  // ---- Alike means same type ----
27	  it.todo("2 runes + 1 moonstone — base 75 G (no block: different types)");
28	  it.todo("3 runes + 3 moonstones — base 120 G (two separate blocks)");
29	
30	  // ---- Modifier scope: cursed surcharge applies only to cursed item's base ----
31	  it.todo("policy with cursed sword + plain amulet — base 160 + 50 curse = 210 G before policy modifiers");
32	
33	  // ---- Modifier thresholds ----
34	  it.todo("customer with exactly 2 years — loyalty discount applies");
35	  it.todo("sword enchantment 5 — high-enchantment surcharge applies");
36	  it.todo("cursed sword enchantment 5 — both curse and high-enchantment surcharges apply");
37	  it.todo("sword enchantment 4 — no high-enchantment surcharge");
38	
39	  // ---- Integration example: newcomer cursed sword ----
40	  it.todo("newcomer (0 years) cursed sword enchantment 3 — premium 165 G");
41	
42	  // ---- Integration example: long-standing customer second contract ----
43	  it.todo("long-standing customer (3 years), second contract, cursed sword enchantment 7 — premium 160 G");
44	
45	  // ---- Rounding ----
46	  it.todo("premium calculation that yields 197.5 G — rounded up to 198 G (MHPCO favor)");
47	
48	  // ---- Claim processing: simple deductible ----
49	  it.todo("regular sword (steel, enchantment 3), damage 500 G — payout 400 G (500 - 100 deductible)");
50	  it.todo("damage to a rune (insurance 250 G), damage 200 G — payout 100 G (full minus deductible)");
51	
52	  // ---- Claim processing: high enchantment 50% clause ----
53	  it.todo("dragon-material sword enchantment 8, damage 1000 G — payout 400 G (50% then deductible)");
54	  it.todo("dragon-material sword enchantment 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
55	  it.todo("dragon-material sword enchantment 5, damage 800 G — payout 700 G (full minus deductible)");
56	  it.todo("steel sword enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");
57	
58	  // ---- Deductible per damage event (per damaged item) ----
59	  it.todo("dragon attack damages sword 500 + amulet 300 — payout 600 G (100 deductible per item)");
60	
61	  // ---- Multiple items of the same type ----
62	  it.todo("policy with two swords — insurance sum 2000 G, cap 4000 G");
63	  it.todo("two swords, both damaged by dragon, each with own deductible");
64	  it.todo("damages references more items of a type than policy covers — CLI exits non-zero");
65	
66	  // ---- Cap exhaustion ----
67	  it.todo("sword + amulet policy — insurance sum 1600 G, cap 3200 G");
68	  it.todo("cursed sword (premium with modifiers 165 G) — cap 2000 G (based on unmodified insurance value)");
69	  it.todo("sword + 3 runes — insurance sum 1750 G (block discount affects premium only)");
70	  it.todo("sword (cap 2000), successive claims of 1500 G — first payout 1400 (cap 600), second payout 600 (cap 0)");
71	
72	  // ---- Rounding for claims ----
73	  it.todo("payout calculation that yields 350.5 G — rounded down to 350 G (MHPCO favor)");
74	
75	  // ---- Edge cases ----
76	  it.todo("unknown item type in quote — CLI exits non-zero, writes error to stderr");
77	  it.todo("claim references item not in policy — CLI exits non-zero, writes error to stderr");
78	  it.todo("claim damage entry with negative amount — CLI exits non-zero, writes error to stderr");
79	
80	  // ---- CLI integration ----
81	  it.todo("CLI reads scenario from stdin and writes results to stdout in correct order");
82	});
